关键观察：如果 L/n 和 R/n 不相等，说明区间 [L, R] 跨越了 n 的倍数，此时一定可以取到 n − 1。否则最大余数为 R mod n。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, L, R;
    cin >> n >> L >> R;
    if (L / n != R / n) {
        cout << n - 1 << endl;
    } else {
        cout << R % n << endl;
    }
    return 0;
}
```

n 为奇数则输出 −1。否则将 n 的二进制分解。从大到小枚举 2 的幂，若 n 包含该次幂则输出。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin >> n;
    if (n % 2 == 1) {
        cout << -1 << endl;
        return 0;
    }
    for (int i = 30; i >= 1; i--) {
        int p = 1 << i;
        if (n >= p) {
            cout << p << ' ';
            n -= p;
        }
    }
    cout << endl;
    return 0;
}
```

最简单的入门题。遍历字符串，cnt += (s[i] == '1')。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    string s;
    cin >> s;
    int cnt = 0;
    for (char c : s)
        if (c == '1') cnt++;
    cout << cnt << endl;
    return 0;
}
```

注意输入可能包含空格，使用 getline 读入整行。遍历字符串统计 s[i] != ' ' 的字符个数。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    string s;
    getline(cin, s);
    int cnt = 0;
    for (char c : s)
        if (c != ' ') cnt++;
    cout << cnt << endl;
    return 0;
}
```
